import {
  GET_NETWORK_ASYNC,
  GET_NETWORK_FAILED,
  GET_NETWORK_PROGRESS,
  GET_NETWORK_SUCCESS,
  GET_REVIEWS_PROGRESS,
  GET_REVIEWS_SUCCESS,
  GET_REVIEWS_FAILED,
  GET_REVIEWS_ASYNC,
  UPDATE_DATA_NETWORK,
  CREATE_REVIEW_PROGRESS,
  CREATE_REVIEW_FAILED,
  CREATE_REVIEW_SUCCESS,
  CREATE_REVIEW_ASYNC,
  CLEAR_USER_SELECTED,
  USER_SELECTED,
} from './contants';

// action saga
export const getNetworkAsync = (payload: {
  keyword?: string;
  page?: number;
  pageSize?: number;
  isLoadMore?: boolean;
  isRefresh?: boolean;
}) => ({ type: GET_NETWORK_ASYNC, payload } as const);
export const getReviewsAsync = (payload: { userId: string }) =>
  ({ type: GET_REVIEWS_ASYNC, payload } as const);

// action reducer
export const getNetworkSuccess = (payload: any) =>
  ({ type: GET_NETWORK_SUCCESS, payload } as const);
export const getNetworkFailed = (payload: any) =>
  ({ type: GET_NETWORK_FAILED, payload } as const);
export const getNetworkProgress = (payload: boolean) =>
  ({ type: GET_NETWORK_PROGRESS, payload } as const);
export const updateDataNetwork = (payload: any) =>
  ({ type: UPDATE_DATA_NETWORK, payload } as const);

export const getReviewsSuccess = (payload: any) =>
  ({ type: GET_REVIEWS_SUCCESS, payload } as const);
export const getReviewsFailed = (payload: any) =>
  ({ type: GET_REVIEWS_FAILED, payload } as const);
export const getReviewsProgress = (payload: boolean) =>
  ({ type: GET_REVIEWS_PROGRESS, payload } as const);

export const createReviewAsync = (payload: {
  userId: string;
  rating: number;
  comments: string;
  searchText: string;
  refBottomSheetClose: any;
}) => ({ type: CREATE_REVIEW_ASYNC, payload } as const);
export const createReviewSuccess = (payload: any) =>
  ({ type: CREATE_REVIEW_SUCCESS, payload } as const);
export const createReviewFailed = (payload: any) =>
  ({ type: CREATE_REVIEW_FAILED, payload } as const);
export const createReviewProgress = (payload: boolean) =>
  ({ type: CREATE_REVIEW_PROGRESS, payload } as const);

export const userSelected = (payload: any) =>
  ({ type: USER_SELECTED, payload } as const);
export const clearUserSelected = () => ({ type: CLEAR_USER_SELECTED } as const);

export const actionNetwork = {
  getNetworkAsync,
  getNetworkSuccess,
  getNetworkFailed,
  getNetworkProgress,
  createReviewAsync,
  createReviewSuccess,
  createReviewFailed,
  createReviewProgress,
  userSelected,
  clearUserSelected,
};

export const actionReviews = {
  getReviewsAsync,
  getReviewsSuccess,
  getReviewsFailed,
  getReviewsProgress,
};

export type NetworkAction = ReturnType<
  | typeof getNetworkAsync
  | typeof getNetworkSuccess
  | typeof getNetworkFailed
  | typeof getNetworkProgress
  | typeof getReviewsAsync
  | typeof getReviewsSuccess
  | typeof getReviewsFailed
  | typeof getReviewsProgress
  | typeof updateDataNetwork
  | typeof createReviewAsync
  | typeof createReviewSuccess
  | typeof createReviewFailed
  | typeof createReviewProgress
  | typeof userSelected
  | typeof clearUserSelected
>;
