import {
  GET_WORK_ORDER_DETAIL_SUCCESS,
  GET_WORK_ORDER_DETAIL_FAILED,
  GET_WORK_ORDER_DETAIL_PROGRESS,
  CLEAR_WORK_ORDER_DETAIL,
  GET_MATERIAL_LIST_SUCCESS,
  GET_MATERIAL_LIST_FAILED,
  GET_CHAT_GROUP_SUCCESS,
  GET_CHAT_GROUP_PROGRESS,
  GET_CHAT_GROUP_FAILED,
  CLEAR_CHECKLIST,
  GET_CHECKLIST_PROGRESS,
  GET_CHECKLIST_FAILED,
  GET_CHECKLIST_SUCCESS,
  GET_COMMENT_CHECKLIST_SUCCESS,
  GET_COMMENT_CHECKLIST_FAILED,
  SAVE_WORK_ORDER_CHECKLIST_SUCCESS,
  SAVE_WORK_ORDER_CHECKLIST_FAILED,
  SAVE_WORK_ORDER_CHECKLIST_PROGRESS,
} from './contants';
import { JobDetailAction } from './actions';
import { JobDetailState } from './types';

export const initialState: JobDetailState = {
  workOrder: {
    data: null,
    isLoading: false,
    error: null,
  },
  materialList: {
    data: null,
    isLoading: false,
    error: null,
  },
  chatGroup: {
    data: null,
    isLoading: false,
    error: null,
  },
  checklists: {
    data: [],
    isLoading: false,
    error: null,
  },
  saveWorkOrder: {
    data: null,
    isLoading: false,
    error: null,
  },
};

export default function jobDetailReducer(
  state = initialState,
  action: JobDetailAction,
): JobDetailState {
  switch (action.type) {
    case GET_WORK_ORDER_DETAIL_SUCCESS:
      return {
        ...state,
        workOrder: {
          ...state.workOrder,
          isLoading: false,
          error: null,
          data: action.payload,
        },
      };
    case GET_WORK_ORDER_DETAIL_FAILED:
      return {
        ...state,
        workOrder: {
          ...state.workOrder,
          isLoading: false,
          error: action.payload,
          data: null,
        },
      };
    case GET_WORK_ORDER_DETAIL_PROGRESS:
      return {
        ...state,
        workOrder: {
          ...state.workOrder,
          isLoading: action.payload,
        },
      };
    case CLEAR_WORK_ORDER_DETAIL:
      return {
        ...initialState,
      };

    case GET_MATERIAL_LIST_SUCCESS:
      return {
        ...state,
        materialList: {
          ...state.materialList,
          isLoading: false,
          error: null,
          data: action.payload,
        },
      };
    case GET_MATERIAL_LIST_FAILED:
      return {
        ...state,
        materialList: {
          ...state.materialList,
          isLoading: false,
          error: action.payload,
          data: null,
        },
      };

    case GET_COMMENT_CHECKLIST_SUCCESS:
      return {
        ...state,
        checklists: {
          ...state.checklists,
          data: state.checklists.data.map(item =>
            item.id === action.payload.id
              ? {
                  ...item,
                  isChecked: action.payload.isChecked,
                  isNA: action.payload.isNA,
                  response: action.payload.responses || action.payload.response,
                  fileEntities: [], // Clear local files after successful submission
                }
              : item,
          ),
        },
      };
    case GET_COMMENT_CHECKLIST_FAILED:
      return {
        ...state,
        checklists: {
          ...state.checklists,
          error: action.payload,
        },
      };

    case GET_CHAT_GROUP_SUCCESS:
      return {
        ...state,
        chatGroup: {
          ...state.chatGroup,
          isLoading: false,
          error: null,
          data: action.payload,
        },
      };

    case GET_CHAT_GROUP_FAILED:
      return {
        ...state,
        chatGroup: {
          ...state.chatGroup,
          isLoading: false,
          error: action.payload,
          data: null,
        },
      };

    case GET_CHAT_GROUP_PROGRESS:
      return {
        ...state,
        chatGroup: {
          ...state.chatGroup,
          isLoading: action.payload,
        },
      };

    case GET_CHECKLIST_SUCCESS:
      return {
        ...state,
        checklists: {
          ...state.checklists,
          isLoading: false,
          error: null,
          data: action.payload,
        },
      };

    case GET_CHECKLIST_FAILED:
      return {
        ...state,
        checklists: {
          ...state.checklists,
          isLoading: false,
          error: action.payload,
          data: [],
        },
      };

    case GET_CHECKLIST_PROGRESS:
      return {
        ...state,
        checklists: {
          ...state.checklists,
          isLoading: action.payload,
        },
      };

    case CLEAR_CHECKLIST:
      return {
        ...state,
        checklists: {
          data: [],
          isLoading: false,
          error: null,
        },
      };

    case SAVE_WORK_ORDER_CHECKLIST_SUCCESS:
      return {
        ...state,
        saveWorkOrder: {
          ...state.saveWorkOrder,
          isLoading: false,
          error: null,
          data: action.payload,
        },
        // Also update workOrder data since save returns updated work order
        workOrder: {
          ...state.workOrder,
          data: action.payload,
        },
      };
    case SAVE_WORK_ORDER_CHECKLIST_FAILED:
      return {
        ...state,
        saveWorkOrder: {
          ...state.saveWorkOrder,
          isLoading: false,
          error: action.payload,
        },
      };
    case SAVE_WORK_ORDER_CHECKLIST_PROGRESS:
      return {
        ...state,
        saveWorkOrder: {
          ...state.saveWorkOrder,
          isLoading: action.payload,
        },
      };

    default:
      return state;
  }
}
